+        defaultNetworkPolicy: { ingress: "AllowSameNamespace", egress: "AllowAll" },
+      },
+      adoptionPolicy: "Never",
+      deletePolicy: "Keep",
+      propagationPolicy: {
+        type: "Placement",
+        placementProfile: {
+          defaultClusterResourcePlacement: {
+            policy: {
+              placementType: "PickAll",
+              affinity: {
+                clusterAffinity: {
+                  requiredDuringSchedulingIgnoredDuringExecution: {
+                    clusterSelectorTerms: [
+                      {
+                        labelSelector: {
+                          matchLabels: { gpu: "true" },
+                          matchExpressions: [
+                            {
+                              key=[REDACTED]                              operator: "In",
+                              values: ["production1", "production2"],
+                            },
+                          ],
+                        },
+                        propertySelector: {
+                          matchExpressions: [{ name: "zones", operator: "Gt", values: ["1"] }],
+                        },
+                      },
+                    ],
+                  },
+                },
+              },
+              tolerations: [
+                { key=[REDACTED] operator: "Exists", value: "true", effect: "NoSchedule" },
+              ],
+            },
+          },
+        },
+      },
+      location: "eastus",
+    },
+  );
+  console.log(result);
+}
+
+async function main() {
+  await fleetManagedNamespacesCreateOrUpdate();
+}
+
